import numpy as np

# Common backbone idea: The algorithms evaluate unvisited customers by calculating a score based on travel time, waiting time, urgency, and other dynamic factors to determine the next customer to visit.

# New algorithm description: {Integrate a machine learning-inspired approach by using a predictive model that estimates the total delivery time for each unvisited customer, balancing delivery time and compliance with time windows, to dynamically determine the next node to visit.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def predictive_model(travel_time, customer_index):
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[customer_index]

        if arrival_time > end_window:
            return float('inf')

        wait_time = max(0, start_window - arrival_time)
        time_until_window_ends = end_window - arrival_time

        # The model predicts a score based on estimated total time and time window compliance
        score = travel_time + wait_time + (1 / (1 + np.exp(-time_until_window_ends)))
        return score

    best_node = None
    best_score = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        score = predictive_model(travel_time, index)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node
